/* ================================
   DeliveryHub Wiki Theme - Default
   Scope: .wiki-content
   ================================ */

.wiki-content {
  /* Typography */
  font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji";
  font-size: 16px;
  line-height: 1.65;
  color: #0f172a; /* slate-900 */
  letter-spacing: 0.1px;

  /* Layout */
  max-width: 920px;
  margin: 0 auto;
  padding: 24px 20px 48px;

  /* Improve readability on large screens */
  text-rendering: geometricPrecision;
  -webkit-font-smoothing: antialiased;
}

/* Links */
.wiki-content a {
  color: #2563eb; /* blue-600 */
  text-decoration: none;
  font-weight: 600;
}
.wiki-content a:hover {
  text-decoration: underline;
  color: #1d4ed8; /* blue-700 */
}

/* Headings */
.wiki-content h1,
.wiki-content h2,
.wiki-content h3,
.wiki-content h4,
.wiki-content h5,
.wiki-content h6 {
  color: #0b1220;
  margin: 1.25em 0 0.5em;
  line-height: 1.2;
  font-weight: 800;
  letter-spacing: -0.02em;
}

.wiki-content h1 {
  font-size: 2.25rem;
  margin-top: 0.25em;
  padding-bottom: 0.35em;
  border-bottom: 1px solid #e2e8f0; /* slate-200 */
}

.wiki-content h2 {
  font-size: 1.7rem;
  padding-bottom: 0.25em;
  border-bottom: 1px solid #eef2ff; /* indigo-50-ish */
}

.wiki-content h3 {
  font-size: 1.35rem;
}

.wiki-content h4 {
  font-size: 1.1rem;
  font-weight: 750;
  color: #111827; /* gray-900 */
}

.wiki-content h5,
.wiki-content h6 {
  font-size: 0.98rem;
  font-weight: 700;
  color: #334155; /* slate-700 */
}

/* Paragraphs */
.wiki-content p {
  margin: 0.75em 0;
  color: #0f172a;
}

/* Lists */
.wiki-content ul,
.wiki-content ol {
  margin: 0.6em 0 0.9em 1.35em;
  padding: 0;
}

.wiki-content li {
  margin: 0.35em 0;
}

.wiki-content ul li::marker {
  color: #64748b; /* slate-500 */
}

.wiki-content ol li::marker {
  color: #475569; /* slate-600 */
  font-weight: 700;
}

/* Blockquotes */
.wiki-content blockquote {
  margin: 1em 0;
  padding: 0.9em 1em;
  border-left: 4px solid #60a5fa; /* blue-400 */
  background: #f8fafc; /* slate-50 */
  color: #0f172a;
  border-radius: 10px;
}
.wiki-content blockquote p {
  margin: 0.3em 0;
}

/* Horizontal rule */
.wiki-content hr {
  border: none;
  border-top: 1px solid #e2e8f0;
  margin: 1.6em 0;
}

/* Code (inline and blocks) */
.wiki-content code {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 0.95em;
  background: #f1f5f9; /* slate-100 */
  padding: 0.12em 0.35em;
  border-radius: 6px;
  border: 1px solid #e2e8f0; /* slate-200 */
}

.wiki-content pre {
  margin: 1em 0;
  padding: 1em 1.1em;
  overflow: auto;
  border-radius: 14px;
  background: #0b1220; /* deep slate */
  color: #e5e7eb; /* gray-200 */
  border: 1px solid #0f172a;
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.12);
}

.wiki-content pre code {
  background: transparent;
  padding: 0;
  border: none;
  color: inherit;
  font-size: 0.93em;
  line-height: 1.55;
}

/* Tables */
.wiki-content table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  margin: 1.1em 0;
  border: 1px solid #e2e8f0; /* slate-200 */
  border-radius: 14px;
  overflow: hidden;
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.06);
}

.wiki-content th,
.wiki-content td {
  padding: 0.85em 0.9em;
  border-bottom: 1px solid #e2e8f0;
  vertical-align: top;
}

.wiki-content th {
  background: #f8fafc; /* slate-50 */
  color: #0f172a;
  font-weight: 800;
  text-align: left;
}

.wiki-content tr:last-child td {
  border-bottom: none;
}

/* Images */
.wiki-content img {
  max-width: 100%;
  height: auto;
  border-radius: 14px;
  border: 1px solid #e2e8f0;
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.08);
  margin: 0.8em 0;
}

/* Callout boxes (author can use <div class="callout info">...) */
.wiki-content .callout {
  margin: 1.1em 0;
  padding: 0.95em 1em;
  border-radius: 14px;
  border: 1px solid #e2e8f0;
  background: #f8fafc;
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.06);
}

.wiki-content .callout .title {
  font-weight: 900;
  margin-bottom: 0.35em;
  letter-spacing: -0.01em;
}

.wiki-content .callout.info {
  border-left: 6px solid #3b82f6; /* blue-500 */
}

.wiki-content .callout.warn {
  border-left: 6px solid #f59e0b; /* amber-500 */
  background: #fffbeb; /* amber-50 */
}

.wiki-content .callout.danger {
  border-left: 6px solid #ef4444; /* red-500 */
  background: #fef2f2; /* red-50 */
}

.wiki-content .callout.success {
  border-left: 6px solid #22c55e; /* green-500 */
  background: #f0fdf4; /* green-50 */
}

/* Task lists (Markdown-style checkboxes rendered to HTML) */
.wiki-content input[type="checkbox"] {
  transform: translateY(1px);
  margin-right: 0.5em;
}

/* Small "meta" text */
.wiki-content .muted {
  color: #64748b; /* slate-500 */
  font-size: 0.95em;
}

/* Subtle selection highlight */
.wiki-content ::selection {
  background: rgba(37, 99, 235, 0.18);
}

/* Responsive */
@media (max-width: 720px) {
  .wiki-content {
    padding: 18px 14px 40px;
    font-size: 15.5px;
  }

  .wiki-content h1 { font-size: 1.9rem; }
  .wiki-content h2 { font-size: 1.5rem; }
  .wiki-content h3 { font-size: 1.25rem; }
}

/* (4) Cards layout system */
.wiki-content .cards {
  display: grid;
  grid-template-columns: repeat(12, minmax(0, 1fr));
  gap: 14px;
  margin: 1.2em 0;
}

.wiki-content .card {
  grid-column: span 12;
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 18px;
  padding: 16px 16px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.07), 0 1px 3px rgba(0, 0, 0, 0.06);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  position: relative;
  overflow: hidden;
  transform-style: preserve-3d;
  will-change: transform;
  cursor: pointer;
}

.wiki-content .card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(135deg, rgba(79, 70, 229, 0.05), rgba(8, 145, 178, 0.05), rgba(5, 150, 105, 0.05));
  opacity: 0;
  transition: opacity 0.4s ease;
  border-radius: 18px;
  z-index: 0;
}

.wiki-content .card::after {
  content: "";
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.8) 0%, transparent 70%);
  opacity: 0;
  transition: opacity 0.4s ease;
  pointer-events: none;
  z-index: 1;
}

.wiki-content .card:hover {
  transform: translateY(-12px) rotateX(5deg) scale(1.02);
  box-shadow: 
    0 20px 40px rgba(79, 70, 229, 0.15),
    0 15px 25px rgba(0, 0, 0, 0.1),
    0 5px 10px rgba(0, 0, 0, 0.08),
    inset 0 1px 0 rgba(255, 255, 255, 0.6);
  border-color: rgba(79, 70, 229, 0.4);
}

.wiki-content .card:hover::before {
  opacity: 1;
}

.wiki-content .card:hover::after {
  opacity: 0.3;
}

.wiki-content .card:active {
  transform: translateY(-8px) rotateX(3deg) scale(1.01);
  transition: all 0.15s ease;
}

.wiki-content .card-title {
  font-weight: 950;
  letter-spacing: -0.02em;
  margin: 0 0 6px;
  color: #0b1220;
  position: relative;
  z-index: 2;
  transition: color 0.3s ease;
}

.wiki-content .card:hover .card-title {
  color: #4f46e5;
}

.wiki-content .card-meta {
  color: #64748b;
  font-size: 0.92em;
  margin: 0 0 10px;
  position: relative;
  z-index: 2;
}

.wiki-content .card p {
  margin: 0.55em 0;
  position: relative;
  z-index: 2;
}

/* Optional accent stripe */
.wiki-content .card.accent::before {
  content: "";
  position: absolute;
  inset: 0 0 auto 0;
  height: 5px;
  background: linear-gradient(90deg, rgba(79,70,229,0.92), rgba(8,145,178,0.85), rgba(5,150,105,0.75));
  z-index: 2;
  opacity: 1;
}

.wiki-content .card.accent:hover::before {
  height: 6px;
  box-shadow: 0 2px 8px rgba(79, 70, 229, 0.4);
}

/* Responsive cards */
@media (min-width: 720px) {
  .wiki-content .card { padding: 18px 18px; }
  .wiki-content .card.span-6 { grid-column: span 6; }
  .wiki-content .card.span-4 { grid-column: span 4; }
  .wiki-content .card.span-3 { grid-column: span 3; }
}

