  border: none;
  border-top: 1px solid #e2e8f0;
  margin: 1.6em 0;
}

/* Code (inline and blocks) */
.wiki-content code {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 0.95em;
  background: #f1f5f9; /* slate-100 */
  padding: 0.12em 0.35em;
  border-radius: 6px;
  border: 1px solid #e2e8f0; /* slate-200 */
}

.wiki-content pre {
  margin: 1em 0;
  padding: 1em 1.1em;
  overflow: auto;
  border-radius: 14px;
  background: #0b1220; /* deep slate */
  color: #e5e7eb; /* gray-200 */
  border: 1px solid #0f172a;
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.12);
}

.wiki-content pre code {
  background: transparent;
  padding: 0;
  border: none;
  color: inherit;
  font-size: 0.93em;
  line-height: 1.55;
}

/* Tables */
.wiki-content table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  margin: 1.5em 0;
  border: 1px solid #e2e8f0; /* slate-200 */
  border-radius: 14px;
  overflow: hidden;
  box-shadow: 
    0 10px 24px rgba(2, 6, 23, 0.08),
    0 4px 8px rgba(0, 0, 0, 0.04),
    inset 0 1px 0 rgba(255, 255, 255, 0.6);
  background: #ffffff;
  transition: box-shadow 0.3s ease;
}

.wiki-content table:hover {
  box-shadow: 
    0 15px 35px rgba(37, 99, 235, 0.12),
    0 8px 12px rgba(0, 0, 0, 0.06),
    inset 0 1px 0 rgba(255, 255, 255, 0.8);
}

.wiki-content th,
.wiki-content td {
  padding: 1em 1.1em;
  border-bottom: 1px solid #e2e8f0;
  vertical-align: top;
  transition: all 0.2s ease;
}

.wiki-content th {
  background: linear-gradient(to bottom, #f8fafc 0%, #f1f5f9 100%); /* slate gradient */
  color: #0f172a;
  font-weight: 800;
  text-align: left;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  font-size: 0.85em;
  border-bottom: 2px solid #3b82f6; /* blue-500 accent */
  position: relative;
}

.wiki-content th::after {
  content: "";
  position: absolute;
  bottom: -2px;
  left: 0;
  right: 0;
  height: 2px;
  background: linear-gradient(90deg, #3b82f6, #2563eb, #1d4ed8);
  opacity: 0;
  transition: opacity 0.3s ease;
}

.wiki-content table:hover th::after {
  opacity: 1;
}

.wiki-content tbody tr {
  transition: all 0.2s ease;
  position: relative;
}

.wiki-content tbody tr::before {
  content: "";
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 4px;
  background: linear-gradient(135deg, #3b82f6, #2563eb);
  opacity: 0;
  transition: opacity 0.2s ease;
  border-radius: 0 4px 4px 0;
}

.wiki-content tbody tr:hover {
  background: linear-gradient(to right, rgba(59, 130, 246, 0.04), rgba(59, 130, 246, 0.02));
  transform: scale(1.005);
  box-shadow: 0 2px 8px rgba(59, 130, 246, 0.08);
}

.wiki-content tbody tr:hover::before {
  opacity: 1;
}

.wiki-content tbody tr:hover td {
  color: #0b1220;
}

.wiki-content tbody tr:nth-child(even) {
  background: rgba(248, 250, 252, 0.5); /* subtle zebra striping */
}

.wiki-content tbody tr:nth-child(even):hover {
  background: linear-gradient(to right, rgba(59, 130, 246, 0.06), rgba(59, 130, 246, 0.03));
}

.wiki-content tr:last-child td {
  border-bottom: none;
}

.wiki-content td {
  color: #334155; /* slate-700 */
}

.wiki-content td:first-child {
  font-weight: 600;
  color: #1e293b; /* slate-800 */
}

/* Responsive table scroll on small screens */
@media (max-width: 720px) {
  .wiki-content table {
    display: block;
    overflow-x: auto;
    white-space: nowrap;
    -webkit-overflow-scrolling: touch;
  }

  .wiki-content th,
  .wiki-content td {
    padding: 0.75em 0.85em;
  }
}

/* Images */
.wiki-content img {
  max-width: 100%;
  height: auto;
  border-radius: 14px;
  border: 1px solid #e2e8f0;
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.08);
  margin: 0.8em 0;
}

/* Callout boxes (author can use <div class="callout info">...) */
.wiki-content .callout {
  margin: 1.1em 0;
  padding: 0.95em 1em;
  border-radius: 14px;
  border: 1px solid #e2e8f0;
  background: #f8fafc;
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.06);
}

.wiki-content .callout .title {
  font-weight: 900;
  margin-bottom: 0.35em;
  letter-spacing: -0.01em;
}

.wiki-content .callout.info {
  border-left: 6px solid #3b82f6; /* blue-500 */
}

.wiki-content .callout.warn {
  border-left: 6px solid #f59e0b; /* amber-500 */
  background: #fffbeb; /* amber-50 */
}

.wiki-content .callout.danger {
  border-left: 6px solid #ef4444; /* red-500 */
  background: #fef2f2; /* red-50 */
}

.wiki-content .callout.success {
  border-left: 6px solid #22c55e; /* green-500 */
  background: #f0fdf4; /* green-50 */
}

/* Task lists (Markdown-style checkboxes rendered to HTML) */
.wiki-content input[type="checkbox"] {
  transform: translateY(1px);
  margin-right: 0.5em;
}

/* Small "meta" text */
.wiki-content .muted {
  color: #64748b; /* slate-500 */
  font-size: 0.95em;
}

/* Subtle selection highlight */
.wiki-content ::selection {
  background: rgba(37, 99, 235, 0.18);
}

/* Responsive */
@media (max-width: 720px) {
  .wiki-content {
    padding: 18px 14px 40px;
    font-size: 15.5px;
  }

  .wiki-content h1 { font-size: 1.9rem; }
  .wiki-content h2 { font-size: 1.5rem; }
  .wiki-content h3 { font-size: 1.25rem; }
}

/* (4) Cards layout system */
.wiki-content .cards {
  display: grid;
  grid-template-columns: repeat(12, minmax(0, 1fr));
  gap: 14px;
  margin: 1.2em 0;
}

.wiki-content .card {
  grid-column: span 12;
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 18px;
  padding: 16px 16px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.07), 0 1px 3px rgba(0, 0, 0, 0.06);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  position: relative;
  overflow: hidden;
  transform-style: preserve-3d;
  will-change: transform;
  cursor: pointer;
}

.wiki-content .card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(135deg, rgba(79, 70, 229, 0.05), rgba(8, 145, 178, 0.05), rgba(5, 150, 105, 0.05));
  opacity: 0;
  transition: opacity 0.4s ease;
  border-radius: 18px;
  z-index: 0;
}

.wiki-content .card::after {
  content: "";
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255, 255, 255, 0.8) 0%, transparent 70%);
  opacity: 0;
  transition: opacity 0.4s ease;
  pointer-events: none;
  z-index: 1;
}

.wiki-content .card:hover {
  transform: translateY(-12px) rotateX(5deg) scale(1.02);
  box-shadow: 
    0 20px 40px rgba(79, 70, 229, 0.15),
    0 15px 25px rgba(0, 0, 0, 0.1),
    0 5px 10px rgba(0, 0, 0, 0.08),
    inset 0 1px 0 rgba(255, 255, 255, 0.6);
  border-color: rgba(79, 70, 229, 0.4);
}

.wiki-content .card:hover::before {
  opacity: 1;
}

.wiki-content .card:hover::after {
  opacity: 0.3;
}

.wiki-content .card:active {
  transform: translateY(-8px) rotateX(3deg) scale(1.01);
  transition: all 0.15s ease;
}

.wiki-content .card-title {
  font-weight: 950;
  letter-spacing: -0.02em;
  margin: 0 0 6px;
  color: #0b1220;
  position: relative;
  z-index: 2;
  transition: color 0.3s ease;
}

.wiki-content .card:hover .card-title {
  color: #4f46e5;
}

.wiki-content .card-meta {
  color: #64748b;
  font-size: 0.92em;
  margin: 0 0 10px;
  position: relative;
  z-index: 2;
}

.wiki-content .card p {
  margin: 0.55em 0;
  position: relative;
  z-index: 2;
}

/* Optional accent stripe */
.wiki-content .card.accent::before {
  content: "";
  position: absolute;
  inset: 0 0 auto 0;
  height: 5px;
  background: linear-gradient(90deg, rgba(79,70,229,0.92), rgba(8,145,178,0.85), rgba(5,150,105,0.75));
  z-index: 2;
  opacity: 1;
}

.wiki-content .card.accent:hover::before {
  height: 6px;
  box-shadow: 0 2px 8px rgba(79, 70, 229, 0.4);
}

/* Responsive cards */
@media (min-width: 720px) {
  .wiki-content .card { padding: 18px 18px; }
  .wiki-content .card.span-6 { grid-column: span 6; }
  .wiki-content .card.span-4 { grid-column: span 4; }
  .wiki-content .card.span-3 { grid-column: span 3; }
}

/* ================================
   NexusDelivery Wiki Theme — Aurora
   Scope: .wiki-content
   ================================ */

.wiki-content.theme-aurora {
  /* Palette */
  --bg: #ffffff;
  --text: #0b1220;         /* deep slate */
  --muted: #64748b;        /* slate-500 */
  --border: #e5e7eb;       /* gray-200 */
  --soft: #f8fafc;         /* slate-50 */

  --primary: #2563eb;      /* blue-600 */
  --primary-700: #1d4ed8;  /* blue-700 */

  --accent-1: #8b5cf6;     /* violet-500 */
  --accent-2: #06b6d4;     /* cyan-500 */
  --accent-3: #22c55e;     /* green-500 */
  --warn: #f59e0b;         /* amber-500 */

  /* Table colors */
  --table-head: #0b1220;
  --table-head-text: #ffffff;
  --row-a: #ffffff;
  --row-b: #f8fafc;
  --row-hover: rgba(37, 99, 235, 0.08);

  /* Code */
  --code-bg: #0b1220;
  --code-text: #e5e7eb;
  --inline-code-bg: #f1f5f9;

  /* Typography & layout */
  font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji",
    "Segoe UI Emoji";
  font-size: 16px;
  line-height: 1.75;
  color: var(--text);
  letter-spacing: 0.1px;
  background: transparent;
  text-rendering: geometricPrecision;
  -webkit-font-smoothing: antialiased;
}

/* Links */
.wiki-content.theme-aurora a {
  color: var(--primary);
  text-decoration: none;
  font-weight: 650;
}
.wiki-content.theme-aurora a:hover {
  color: var(--primary-700);
  text-decoration: underline;
  text-decoration-thickness: 2px;
  text-underline-offset: 3px;
}

/* Headings */
.wiki-content.theme-aurora h1,
.wiki-content.theme-aurora h2,
.wiki-content.theme-aurora h3,
.wiki-content.theme-aurora h4,
.wiki-content.theme-aurora h5,
.wiki-content.theme-aurora h6 {
  color: var(--text);
  line-height: 1.18;
  font-weight: 900;
  letter-spacing: -0.02em;
  margin: 1.2em 0 0.55em;
}

.wiki-content.theme-aurora h1 {
  font-size: 2.25rem;
  margin-top: 0.2em;
  padding-bottom: 0.35em;
  border-bottom: 1px solid var(--border);
  position: relative;
}
.wiki-content.theme-aurora h1::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: -1px;
  height: 3px;
  width: 140px;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--accent-1), var(--accent-2), var(--accent-3));
}

.wiki-content.theme-aurora h2 {
  font-size: 1.6rem;
  padding-left: 0.6rem;
  border-left: 5px solid var(--accent-2);
}
.wiki-content.theme-aurora h3 {
  font-size: 1.28rem;
  color: #111827;
}
.wiki-content.theme-aurora h4 {
  font-size: 1.06rem;
  color: #111827;
}
.wiki-content.theme-aurora h5,
.wiki-content.theme-aurora h6 {
  font-size: 0.98rem;
  color: #334155;
  font-weight: 800;
}

/* Paragraphs & small text */
.wiki-content.theme-aurora p {
  margin: 0.8em 0;
  color: var(--text);
}
.wiki-content.theme-aurora .muted {
  color: var(--muted);
  font-size: 0.95em;
}

/* Lists */
.wiki-content.theme-aurora ul,
.wiki-content.theme-aurora ol {
  margin: 0.65em 0 1em 1.35em;
}
.wiki-content.theme-aurora li {
  margin: 0.35em 0;
}
.wiki-content.theme-aurora ul li::marker {
  color: var(--accent-1);
}
.wiki-content.theme-aurora ol li::marker {
  color: #475569;
  font-weight: 800;
}

/* HR */
.wiki-content.theme-aurora hr {
  border: none;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--border), transparent);
  margin: 1.6em 0;
}

/* Blockquote */
.wiki-content.theme-aurora blockquote {
  margin: 1.1em 0;
  padding: 1em 1.05em;
  border-left: 5px solid var(--accent-1);
  background: linear-gradient(0deg, rgba(139, 92, 246, 0.06), rgba(6, 182, 212, 0.04));
  border-radius: 14px;
  color: var(--text);
  box-shadow: 0 10px 24px rgba(2, 6, 23, 0.06);
}
.wiki-content.theme-aurora blockquote p {
  margin: 0.35em 0;
}

/* Inline code */
.wiki-content.theme-aurora code {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 0.95em;
  background: var(--inline-code-bg);
  padding: 0.12em 0.35em;
  border-radius: 8px;
  border: 1px solid #e2e8f0;
}

/* Code blocks */
.wiki-content.theme-aurora pre {
  margin: 1.05em 0;
  padding: 1.05em 1.1em;
  overflow: auto;
  border-radius: 16px;
  background: var(--code-bg);
  color: var(--code-text);
  border: 1px solid #0f172a;
  box-shadow: 0 18px 40px rgba(2, 6, 23, 0.18);
}
.wiki-content.theme-aurora pre code {
  background: transparent;
  padding: 0;
  border: none;
  color: inherit;
  font-size: 0.93em;
  line-height: 1.6;
}

/* Tables: alternating rows + hover */
.wiki-content.theme-aurora table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  margin: 1.15em 0;
  border: 1px solid var(--border);
  border-radius: 16px;
  overflow: hidden;
  box-shadow: 0 14px 34px rgba(2, 6, 23, 0.08);
}

.wiki-content.theme-aurora thead th,
.wiki-content.theme-aurora th {
  background: linear-gradient(90deg, #0b1220, #111827);
  color: var(--table-head-text);
  font-weight: 900;
  text-align: left;
  padding: 0.9em 0.95em;
  border-bottom: 1px solid rgba(255, 255, 255, 0.12);
}

.wiki-content.theme-aurora td {
  padding: 0.85em 0.95em;
  border-bottom: 1px solid var(--border);
  vertical-align: top;
  color: #0f172a;
}

.wiki-content.theme-aurora tbody tr:nth-child(odd) td {
  background: var(--row-a);
}
.wiki-content.theme-aurora tbody tr:nth-child(even) td {
  background: var(--row-b);
}

/* Row hover effect */
.wiki-content.theme-aurora tbody tr:hover td {
  background: var(--row-hover);
  transition: background 140ms ease;
}

/* Rounded corners for the table edges */
.wiki-content.theme-aurora table tr:first-child th:first-child {
  border-top-left-radius: 16px;
}
.wiki-content.theme-aurora table tr:first-child th:last-child {
  border-top-right-radius: 16px;
}
.wiki-content.theme-aurora table tr:last-child td {
  border-bottom: none;
}

/* Images */
.wiki-content.theme-aurora img {
  max-width: 100%;
  height: auto;
  border-radius: 16px;
  border: 1px solid var(--border);
  box-shadow: 0 14px 34px rgba(2, 6, 23, 0.10);
  margin: 0.9em 0;
}

/* Callouts (optional) */
.wiki-content.theme-aurora .callout {
  margin: 1.1em 0;
  padding: 1em 1.05em;
  border-radius: 16px;
  border: 1px solid var(--border);
  background: var(--soft);
  box-shadow: 0 12px 28px rgba(2, 6, 23, 0.06);
}
.wiki-content.theme-aurora .callout .title {
  font-weight: 950;
  margin-bottom: 0.35em;
}
.wiki-content.theme-aurora .callout.info { border-left: 6px solid var(--accent-2); }
.wiki-content.theme-aurora .callout.warn { border-left: 6px solid var(--warn); background: #fffbeb; }
.wiki-content.theme-aurora .callout.success { border-left: 6px solid var(--accent-3); background: #f0fdf4; }

/* Selection highlight */
.wiki-content.theme-aurora ::selection {
  background: rgba(139, 92, 246, 0.18);
}

/* Responsive */
@media (max-width: 720px) {
  .wiki-content.theme-aurora {
    font-size: 15.5px;
    line-height: 1.72;
  }
  .wiki-content.theme-aurora h1 { font-size: 1.95rem; }
  .wiki-content.theme-aurora h2 { font-size: 1.45rem; }
  .wiki-content.theme-aurora h3 { font-size: 1.22rem; }
}

